-- 시장 조사 보고서 작성
INSERT INTO task_comments (id, task_id, author_id, body, created_at) VALUES
('80000000-0000-0000-0000-000000000001', '60000000-0000-0000-0000-000000000001', '20000000-0000-0000-0000-000000000003', '시장 조사 범위를 국내로 한정할까요, 해외까지 포함할까요?', '2026-01-20 09:30:00+09'),
('80000000-0000-0000-0000-000000000002', '60000000-0000-0000-0000-000000000001', '20000000-0000-0000-0000-000000000016', '국내 + 동남아 시장까지 포함하면 좋을 것 같습니다. 베트남/인도네시아/태국 3개국 중심으로요.', '2026-01-20 10:15:00+09'),
('80000000-0000-0000-0000-000000000003', '60000000-0000-0000-0000-000000000001', '20000000-0000-0000-0000-000000000002', '좋습니다. 동남아 시장 데이터는 Statista 리포트 참고해주세요. 라이선스 있으니 공유드릴게요.', '2026-01-20 11:00:00+09');

-- 와이어프레임 제작
INSERT INTO task_comments (id, task_id, author_id, body, created_at) VALUES
('80000000-0000-0000-0000-000000000004', '60000000-0000-0000-0000-000000000002', '20000000-0000-0000-0000-000000000012', '메인 화면, 검색, 마이페이지 와이어프레임 초안 올렸습니다. Figma 링크 확인 부탁드려요.', '2026-02-05 14:00:00+09'),
('80000000-0000-0000-0000-000000000005', '60000000-0000-0000-0000-000000000002', '20000000-0000-0000-0000-000000000004', '탭 네비게이션 구조가 깔끔하네요. 알림 센터 진입 동선만 한번 더 검토해주시면 될 것 같아요.', '2026-02-05 15:30:00+09'),
('80000000-0000-0000-0000-000000000006', '60000000-0000-0000-0000-000000000002', '20000000-0000-0000-0000-000000000013', '지민이가 비주얼 시안 작업 중이에요. 다음 주 초에 Hi-Fi 목업 공유드리겠습니다.', '2026-02-06 09:00:00+09');

-- PRD 문서 작성
INSERT INTO task_comments (id, task_id, author_id, body, created_at) VALUES
('80000000-0000-0000-0000-000000000007', '60000000-0000-0000-0000-000000000004', '20000000-0000-0000-0000-000000000003', 'PRD 1차 초안 Notion에 올렸습니다. 각 파트별 리뷰 부탁드려요.', '2026-02-15 10:00:00+09'),
('80000000-0000-0000-0000-000000000008', '60000000-0000-0000-0000-000000000004', '20000000-0000-0000-0000-000000000006', '오프라인 모드 요구사항이 좀 더 구체적이면 좋겠어요. 어떤 데이터까지 로컬 캐싱할지 범위가 필요합니다.', '2026-02-16 11:00:00+09'),
('80000000-0000-0000-0000-000000000009', '60000000-0000-0000-0000-000000000004', '20000000-0000-0000-0000-000000000003', '피드백 반영했습니다. 오프라인 캐싱 범위를 최근 7일 데이터로 명시했고, 동기화 정책도 추가했어요.', '2026-02-17 09:30:00+09');

-- 데이터 소스 목록화
INSERT INTO task_comments (id, task_id, author_id, body, created_at) VALUES
('80000000-0000-0000-0000-000000000010', '60000000-0000-0000-0000-000000000013', '20000000-0000-0000-0000-000000000011', '현재 38개 소스 중 32개 파악 완료. 레거시 배치 6개가 문서가 없어서 DBA팀에 문의 넣었습니다.', '2026-02-10 16:00:00+09'),
('80000000-0000-0000-0000-000000000011', '60000000-0000-0000-0000-000000000013', '20000000-0000-0000-0000-000000000005', 'DBA팀 김과장님한테 확인했는데 그 중 2개는 이미 deprecated 된 소스라고 해요. 34개로 확정하면 될 것 같습니다.', '2026-02-12 10:00:00+09');

-- 사용자 인터뷰
INSERT INTO task_comments (id, task_id, author_id, body, created_at) VALUES
('80000000-0000-0000-0000-000000000012', '60000000-0000-0000-0000-000000000019', '20000000-0000-0000-0000-000000000012', '1차 인터뷰 9명 완료. 공통적으로 대시보드 커스터마이징 요구가 강합니다.', '2026-03-15 14:00:00+09'),
('80000000-0000-0000-0000-000000000013', '60000000-0000-0000-0000-000000000019', '20000000-0000-0000-0000-000000000016', '마케팅팀에서도 고객사 피드백 받은 거 있는데 공유드릴까요? 대시보드 관련 VOC가 좀 있어요.', '2026-03-15 15:30:00+09'),
('80000000-0000-0000-0000-000000000014', '60000000-0000-0000-0000-000000000019', '20000000-0000-0000-0000-000000000012', '네 부탁드려요! 인터뷰 결과랑 합쳐서 인사이트 리포트 만들겠습니다.', '2026-03-15 16:00:00+09');

-- 병행 운영 모니터링
INSERT INTO task_comments (id, task_id, author_id, body, created_at) VALUES
('80000000-0000-0000-0000-000000000015', '60000000-0000-0000-0000-000000000028', '20000000-0000-0000-0000-000000000018', '병행 운영 6주차입니다. 신규 시스템 안정화되어 오류율 0.02% 이하로 내려왔어요.', '2026-03-10 09:00:00+09'),
('80000000-0000-0000-0000-000000000016', '60000000-0000-0000-0000-000000000028', '20000000-0000-0000-0000-000000000003', '훌륭합니다. 3월 말 기준으로 구시스템 셧다운 일정 잡을게요. 재무팀 확인 후 공유하겠습니다.', '2026-03-10 10:00:00+09');
